import styles from './Hero.module.css';

const Hero = () => {
    return (
        <section className={styles.hero}>
            <div className={`${styles.container} container`}>
                <div className={styles.imageSide}>
                    <div className={`${styles.pillImage} ${styles.yellowBorder}`}>
                        <div className={styles.placeholderImg}></div>
                        <div className={styles.decorationLeft}>
                            <span></span><span></span><span></span>
                        </div>
                    </div>
                </div>

                <div className={styles.content}>
                    <h1 className={styles.title}>
                        ابدأ إدارة أكاديميتك <br />
                        <span className={styles.highlight}>بسهولة</span>
                    </h1>
                    <p className={styles.description}>
                        كل الأدوات اللي تحتاجها لإدارة الخدمات، العملاء، والحجوزات في مكان واحد. اختر باقتك وابدأ خلال دقائق.
                    </p>
                    <button className={`${styles.btn} btn btn-primary`}>أختر باقتك الأن</button>
                </div>

                <div className={styles.imageSide}>
                    <div className={`${styles.pillImage} ${styles.blueBorder}`}>
                        <div className={styles.placeholderImg}></div>
                        <div className={styles.decorationRight}>
                            <span></span><span></span><span></span>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Hero;
