import styles from './Pricing.module.css';
import { Check } from 'lucide-react';

const Pricing = () => {
    const plans = [
        {
            name: 'الباقة الأساسية',
            price: '2,500',
            features: [
                'إضافة حتى 50 مدرب',
                'إنشاء حتى 10 دورات / برامج تدريبية',
                'رسائل البريد مجددة للمتدربين',
                'الوصول لاجتماعات افتراضية في التدوين',
                'إمكانية تعديل تقارير مختصرة للمتدربين',
            ],
            buttonText: 'اشترك الآن',
            highlight: false,
        },
        {
            name: 'الباقة البريميوم',
            price: '4,200',
            features: [
                'إضافة حتى 200 مدرب',
                'إنشاء حتى 45 دورة / برامج تدريبية',
                'الوصول لجميع التقارير والإحصائيات التفصيلية',
                'إمكانية تعيين مديرين داخل الأكاديمية',
                'تخصيص الباقات والبرامج التدريبية',
            ],
            buttonText: 'اشترك الآن',
            highlight: true,
            tag: 'الأكثر اختياراً',
        },
        {
            name: 'الباقة الالتر',
            price: '5,200',
            features: [
                'إضافة عدد غير محدود من المدربين',
                'إنشاء عدد غير محدود من الدورات',
                'إرسال تنبيهات غير محدودة للمدربين',
                'إدارة التفرخ بالتحكم الداخلي للأكاديمية',
                'دعم فني متميز ومتاح على مدار الساعة',
            ],
            buttonText: 'اشترك الآن',
            highlight: false,
        },
    ];

    return (
        <section className={styles.pricing}>
            <div className="container">
                <div className={styles.header}>
                    <h2>اختر باقتك وابدأ إدارة أكاديميتك بسهولة</h2>
                    <p>أختر الباقة المناسبة لاحتياجات أكاديميتك وابدأ إدارة المدربين والخدمات بسهولة مع نظام مرن ينمو معك.</p>
                </div>

                <div className={styles.grid}>
                    {plans.map((plan, index) => (
                        <div key={index} className={`${styles.card} ${plan.highlight ? styles.featured : ''}`}>
                            {plan.highlight && <div className={styles.tag}>{plan.tag}</div>}
                            <div className={styles.cardHeader}>
                                <h3 className={styles.planName}>{plan.name}</h3>
                                <div className={styles.price}>
                                    <span className={styles.currency}>SAR</span>
                                    <span className={styles.amount}>{plan.price}</span>
                                </div>
                            </div>

                            <ul className={styles.features}>
                                {plan.features.map((feature, idx) => (
                                    <li key={idx}>
                                        <Check className={styles.check} size={18} />
                                        <span>{feature}</span>
                                    </li>
                                ))}
                            </ul>

                            <button className={`${styles.btn} btn ${plan.highlight ? 'btn-yellow' : 'btn-primary'}`}>
                                {plan.buttonText}
                            </button>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default Pricing;
